INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('MNIT Jaipur', 'fests', 'Fests > Blitzschlag is a 3-day cultural fest held in February at MNIT Jaipur. It is one of Rajasthan''s largest college cultural fests.');
